[124] يُنظر: ((تفسير ابن جرير)) (21/193)، ((تفسير ابن عطية)) (5/112)، ((تفسير السعدي)) (ص: 785)، ((تفسير ابن عاشور)) (26/85). ممَّن اختار أنَّ المعنى: إن تَنصُروا دينَ اللهِ ورسولَه يَنصُرْكم على عدوِّكم: البغويُّ، والزمخشري، وابن الجوزي، والرَّسْعَني، والبيضاوي، والنسفي، والخازن. يُنظر: ((تفسير البغوي)) (4/211)، ((تفسير الزمخشري)) (4/318)، ((تفسير ابن الجوزي)) (4/117)، ((تفسير الرسعني)) (7/253)، ((تفسير البيضاوي)) (5/120)، ((تفسير النسفي)) (3/324)، ((تفسير الخازن)) (4/141). وقال بعضُ المفسِّرينَ: المعنى: إن تَنصُروا دينَ اللهِ يَنصُرْكم على أعدائِكم. وممَّن قال ذلك واقتصَر عليه: السَّمَرْقَنْديُّ، والقرطبي، والعُلَيمي، والشوكاني. يُنظر: ((تفسير السمرقندي)) (3/299)، ((تفسير القرطبي)) (16/232)، ((تفسير العليمي)) (6/312)، ((تفسير الشوكاني)) (5/38). قال الواحدي: (قال أهل المعاني: إن تَنصُروا دينَ اللهِ ورسولَه بالجهادِ، إلَّا أنَّه أُضيفَ النَّصرُ إلى اللهِ تفخيمًا لِشأنِه وتعظيمًا، وتلَطُّفًا في الاستِدعاءِ إليه، كالتَّلطُّفِ في مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ
[البقرة: 245]
). ((البسيط)) (20/226). وقال ابن عطيَّة: (وقولُه تعالى: إِنْ تَنْصُرُوا اللَّهَ فيه حذْفُ مُضافٍ، أي: دينَ اللهِ ورسولَه، والمعنى: تَنصُروه بجِدِّكم واتِّباعِكم وإيمانِكم يَنْصُرْكُمْ بخلْقِ القوَّةِ لكم، والجرأةِ، وغيرِ ذلك مِن المعارِفِ). وفسَّر السعديُّ نصْرَ اللهِ بالقيامِ بدينِه، والدَّعوةِ إليه، وجهادِ أعدائِه، والقَصدِ بذلك وجْهَ الله تعالى. وفسَّر نصْرَ اللهِ لهم وتثبيتَ أقدامِهم بالرَّبطِ على قُلوبِهم بالصَّبرِ والطُّمأنينةِ والثَّباتِ، وأن يُصبِّرَ أجسامَهم على ذلك، ويُعينَهم على أعدائِهم. يُنظر: ((تفسير السعدي)) (ص: 785). وقال البِقاعي: (إِنْ تَنْصُرُوا اللَّهَ أي: يَتجدَّدْ لكم نيَّةٌ مُستمِرَّةٌ وفِعلٌ دائمٌ على نُصرةِ دِينِ الملِكِ الأعظَمِ، بإيضاحِ أدلَّتِه وتَبيينِها، وتَوهيةِ شُبَهِ أهلِ الباطلِ وقتالِهم، ويكونُ ذلك خالصًا له). ((نظم الدرر)) (18/209). قال السمعاني: (والنَّصرُ مِن الله: هو الحِفظُ والهِدايةُ. وعن قَتادةَ قال: مَن يَنصُرِ اللهَ يَنصُرْه، ومَن يَسألْه يُعِطْه. ويُقالُ: يَنصُرْكم بتَغليبِكم على عدوِّكم، وإعلائِكم عليهم). ((تفسير السمعاني)) (5/170).

[578] يُنظر: ((تفسير ابن جرير)) (21/230)، ((تفسير ابن عطية)) (5/123)، ((تفسير ابن كثير)) (7/323)، ((نظم الدرر)) للبقاعي (18/264، 265)، ((تفسير السعدي)) (ص: 790). قال الرازيُّ: (اللَّعِبُ: ما تَشتَغِلُ به ولا يكونُ فيه ضَرورةٌ في الحالِ، ولا مَنفعةٌ في المآلِ، ثمَّ إنِ استَعمَلَه الإنسانُ، ولم يَشغَلْه عن غيرِه، ولم يَثْنِه عن أشغالِه المُهِمَّةِ؛ فهو لَعِبٌ، وإن شَغَلَه ودَهَشَه عن مُهِمَّاتِه فهو لَهوٌ، ولهذا يُقالُ: مَلاهٍ لآلاتِ الملاهي؛ لأنَّها مَشْغلةٌ عن الغيرِ، ويقالُ لِما دونَه لَعِبٌ، كاللَّعِبِ بالشِّطْرَنجِ والحَمامِ). ((تفسير الرازي)) (28/62). وقال أبو هلالٍ العسكريُّ: (الفرقُ بيْنَ اللَّهْوِ واللَّعِبِ: أنَّه لا لَهْوَ إلَّا لَعِبٌ، وقد يكونُ لَعِبٌ ليس بِلَهْوٍ...، وإنَّما اللَّهوُ لَعِبٌ لا يُعقِبُ نفعًا. وسُمِّيَ لَهْوًا؛ لأنَّه يَشغَلُ عما يَعني، مِن قولِهم: ألْهاني الشَّيءُ، أي: شغَلَني، ومنه قولُه تعالى: أَلْهَاكُمُ التَّكَاثُرُ
[التكاثر: 1]
). ((الفروق اللغوية)) (ص: 254). وقال السعديُّ: (لَعِبٌ في الأبدانِ، ولهوٌ في القُلوبِ). ((تفسير السعدي)) (ص: 790). وقال ابنُ عاشور: (اللَّعِبُ: الفِعلُ الَّذي يريدُ به فاعِلُه الهَزْلَ دونَ اجتِناءِ فائدةٍ، كأفعالِ الصِّبيانِ في مَرَحِهم. واللَّهوُ: العمَلُ الَّذي يُعمَلُ لِصَرفِ العَقلِ عن تَعَبِ الجِدِّ في الأُمورِ، فيَلهو عمَّا يَهتَمُّ له، ويَكِدُّ عَقْلَه). ((تفسير ابن عاشور)) (26/133). وقيل: اللَّهوُ واللَّعبُ يَشترِكانِ في أنَّهما اشتِغالٌ بما لا يَعني، مِن هوًى أو طرَبٍ، حرامًا أو لا. قيل: واللَّهوُ أعَمُّ مُطلَقًا، فاستِماعُ الملاهي لَهْوٌ لا لَعِبٌ. وقيل: اللَّعِبُ ما قُصِد به تعجيلُ المسَرَّةِ والاستِرواحُ به، واللَّهوُ ما شغَل مِن هوًى وطرَبٍ وإن لم يُقصَدْ به ذلك. وقيل غيرُ ذلك. يُنظر: ((الكليات)) للكفوي (ص: 799)، ((تاج العروس)) للزَّبِيدي (39/497).
